INSERT INTO `chatbot_settings` VALUES (1,'chatbot_enabled','true','boolean','Bật/Tắt hiển thị chatbot trên website',2,'2026-03-04 09:51:16','2026-03-05 13:44:51'),(2,'chatbot_title','Chatbot Thư Viện','text','Tiêu đề chatbot',2,'2026-03-04 09:51:16','2026-03-05 13:44:51'),(3,'welcome_message','Xin chào! Tôi là trợ lý thư viện TVU. Mình giúp gì được cho bạn?','text','Tin nhắn chào mừng',2,'2026-03-04 09:51:16','2026-03-05 13:44:51'),(4,'primary_color','#1976d2','color','Màu chính của chatbot',2,'2026-03-04 09:51:16','2026-03-05 13:44:51'),(5,'secondary_color','#FFFFFF','color','Màu phụ của chatbot',NULL,'2026-03-04 09:51:16','2026-03-04 09:51:16'),(6,'header_bg_color','#1976d2','color','Màu nền header chatbot',2,'2026-03-04 09:51:16','2026-03-05 13:44:51'),(7,'header_text_color','#ffffff','color','Màu chữ header chatbot',2,'2026-03-04 09:51:16','2026-03-05 13:44:51'),(8,'user_bubble_color','#e3f2fd','color','Màu bong bóng chat người dùng',2,'2026-03-04 09:51:16','2026-03-05 13:44:51'),(9,'bot_bubble_color','#f5f5f5','color','Màu bong bóng chat bot',2,'2026-03-04 09:51:16','2026-03-05 13:44:51'),(10,'button_color','#1976d2','color','Màu nút mở chatbot',2,'2026-03-04 09:51:16','2026-03-05 13:44:51'),(11,'button_position','{\"bottom\": \"20px\", \"right\": \"20px\"}','json','Vị trí nút chatbot',NULL,'2026-03-04 09:51:16','2026-03-04 09:51:16'),(12,'bot_avatar','/assets/bot-avatar.png','text','Đường dẫn avatar bot',NULL,'2026-03-04 09:51:16','2026-03-04 09:51:16'),(13,'no_answer_message','Cảm ơn bạn đã đặt câu hỏi! Hiện tại mình chưa tìm thấy thông tin phù hợp cho câu hỏi này. Bạn có thể thử hỏi lại theo cách khác, hoặc liên hệ trực tiếp với thủ thư qua số (02943) 855 246 hoặc email celras@tvu.edu.vn để được hỗ trợ tận tình nhé! ?','text','Tin nhắn khi không tìm thấy câu trả lời',2,'2026-03-04 09:51:16','2026-03-06 10:48:42'),(14,'max_suggestions','5','number','Số câu hỏi gợi ý tối đa',NULL,'2026-03-04 09:51:16','2026-03-04 09:51:16'),(15,'ai_enabled','true','boolean','Bật/Tắt trả lời AI khi không có đáp án',2,'2026-03-11 08:48:26','2026-03-11 08:58:53'),(16,'ai_system_prompt','Bạn là trợ lý thư viện TVU. Trả lời ngắn gọn, đúng trọng tâm. Nếu không chắc, hãy nói bạn chưa có thông tin.','text','System prompt cho AI',2,'2026-03-11 08:48:26','2026-03-11 08:58:53'),(17,'ai_max_tokens','500','number','Số token tối đa cho mỗi câu trả lời AI',2,'2026-03-11 08:48:26','2026-03-11 08:58:53'),(18,'ai_temperature','0.2','number','Độ ngẫu nhiên (temperature) cho AI',2,'2026-03-11 08:48:26','2026-03-11 08:58:53'),(19,'ai_default_model','gemini-2.5-flash','text','Model AI mặc định (dùng khi key không có model riêng)',2,'2026-03-11 08:48:26','2026-03-11 09:19:33'),(20,'match_strict_mode','true','boolean','Ưu tiên độ chính xác khi tìm câu hỏi',2,'2026-03-11 08:48:26','2026-03-11 08:58:53'),(21,'match_min_relevance','0.5','number','Ngưỡng relevance cho FULLTEXT',2,'2026-03-11 08:48:26','2026-03-11 08:58:53'),(22,'match_min_overlap','0.7','number','Tỷ lệ trùng từ khóa tối thiểu',2,'2026-03-11 08:48:26','2026-03-11 08:58:53'),(23,'match_keyword_max_df','14','number','',2,'2026-03-11 09:07:49','2026-03-11 09:07:49');
