DROP TABLE IF EXISTS `datasets`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `datasets` (
  `id` int NOT NULL AUTO_INCREMENT,
  `file_name` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tên file gốc',
  `file_path` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Đường dẫn lưu trữ file',
  `file_type` enum('word','pdf') COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Loại file',
  `file_size` bigint NOT NULL DEFAULT '0' COMMENT 'Kích thước file (bytes)',
  `total_questions` int NOT NULL DEFAULT '0' COMMENT 'Số câu hỏi được import',
  `status` enum('pending','processing','completed','failed') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `error_message` text COLLATE utf8mb4_unicode_ci COMMENT 'Thông báo lỗi nếu import thất bại',
  `uploaded_by` int DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `uploaded_by` (`uploaded_by`),
  CONSTRAINT `datasets_ibfk_1` FOREIGN KEY (`uploaded_by`) REFERENCES `admins` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=28 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Quản lý file dữ liệu được upload (Word, PDF)';
