INSERT INTO `event_themes` VALUES (1,'Mặc định','mac-dinh','#1976D2','#FFFFFF','#1976D2','#FFFFFF','#E3F2FD','#F5F5F5','#1976D2','Roboto, sans-serif',NULL,NULL,NULL,'Xin chào! Tôi là trợ lý thư viện. Bạn cần tôi giúp gì?',NULL,NULL,1,NULL,'2026-03-04 09:51:16','2026-03-09 07:50:23'),(24,'Tết Nguyên Đán','tet','#dc2626','#fbbf24','#dc2626','#ffffff','#fbbf24','#fff1f2','#dc2626','\'Playfair Display\', serif',NULL,'[\"?\",\"?\",\"?\",\"?\",\"?\",\"?\",\"?\"]','Chúc Mừng Năm Mới! ?','Chào mừng năm mới! Chúc bạn năm mới an khang thịnh vượng! ??',NULL,NULL,0,NULL,'2026-03-06 15:20:34','2026-03-06 15:20:34'),(25,'Tết Trung Thu','trung-thu','#f59e0b','#7c3aed','#1e3a5f','#fbbf24','#fef3c7','#ede9fe','#f59e0b','\'Quicksand\', sans-serif',NULL,'[\"?\",\"?\",\"?\",\"?\",\"⭐\",\"?\",\"?\"]','Vui Tết Trung Thu! ?','Chúc bạn Tết Trung Thu vui vẻ! Tôi có thể giúp gì cho bạn? ?',NULL,NULL,0,NULL,'2026-03-06 15:20:34','2026-03-06 15:20:34'),(26,'Halloween','halloween','#f97316','#6b21a8','#1a1a2e','#f97316','#f97316','#3b0764','#f97316','\'Creepster\', cursive',NULL,'[\"?\",\"?\",\"?\",\"?️\",\"?\",\"?️\",\"?\"]','Happy Halloween! ?','Chuyện gì đã đưa bạn đến đây trong đêm Halloween này? ?',NULL,NULL,0,NULL,'2026-03-06 15:20:34','2026-03-06 16:20:56'),(27,'Giáng Sinh','giang-sinh','#16a34a','#dc2626','#0c4a2f','#ffffff','#dc2626','#dcfce7','#16a34a','\'Mountains of Christmas\', cursive',NULL,'[\"?\",\"?\",\"⛄\",\"?\",\"❄️\",\"?\",\"⭐\"]','Merry Christmas! ?','Giáng Sinh vui vẻ! Tôi là trợ lý thư viện, chúc bạn mùa lễ an lành! ❄️',NULL,NULL,0,NULL,'2026-03-06 15:20:34','2026-03-06 15:21:52'),(28,'Quốc tế Phụ nữ 8/3','8-3','#ec4899','#f472b6','#be185d','#ffffff','#ec4899','#fce7f3','#ec4899','\'Dancing Script\', cursive',NULL,'[\"?\",\"?\",\"?\",\"?\",\"?\",\"?\",\"✨\"]','Chúc Mừng 8/3! ?','Chúc mừng Ngày Quốc tế Phụ nữ! Chúc bạn luôn hạnh phúc và đẹp rạng ngời! ?',NULL,NULL,0,NULL,'2026-03-06 15:20:34','2026-03-09 07:50:03'),(29,'Phụ nữ Việt Nam 20/10','20-10','#e11d48','#fb7185','#