--
-- Table structure for table `forms`
--

DROP TABLE IF EXISTS `forms`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `forms` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tên biểu mẫu / giấy tờ',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT 'Mô tả nội dung biểu mẫu',
  `url` varchar(1000) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Đường dẫn tới trang biểu mẫu',
  `keywords` text COLLATE utf8mb4_unicode_ci COMMENT 'Từ khóa nhận diện, phân cách bằng dấu phẩy',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_by` int DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `created_by` (`created_by`),
  CONSTRAINT `forms_ibfk_1` FOREIGN KEY (`created_by`) REFERENCES `admins` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Biểu mẫu / giấy tờ – chatbot trả về link khi hỏi';
/*!40101 SET character_set_client = @saved_cs_client */;

