DROP TABLE IF EXISTS `keywords`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `keywords` (
  `id` int NOT NULL AUTO_INCREMENT,
  `question_id` int NOT NULL,
  `keyword` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Từ khóa liên quan đến câu hỏi',
  `is_auto` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Từ khóa tự động (1) hay thủ công (0)',
  `language` enum('vi','en','both') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'vi' COMMENT 'Ngôn ngữ từ khóa',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `question_id` (`question_id`),
  KEY `idx_keyword` (`keyword`),
  KEY `idx_language` (`language`),
  KEY `idx_is_auto` (`is_auto`),
  CONSTRAINT `keywords_ibfk_1` FOREIGN KEY (`question_id`) REFERENCES `questions` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1211 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Từ khóa để matching câu hỏi người dùng';
/*!40101 SET character_set_client = @saved_cs_client */;

