DROP TABLE IF EXISTS `rag_performance_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rag_performance_log` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_query` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `matched_question_id` int DEFAULT NULL,
  `similarity_score` float DEFAULT NULL COMMENT 'Cosine similarity score',
  `hybrid_score` float DEFAULT NULL COMMENT 'Hybrid score tổng hợp',
  `embedding_score` float DEFAULT NULL COMMENT 'Cosine similarity score thuần túy',
  `keyword_score` float DEFAULT NULL COMMENT 'Keyword overlap score',
  `fulltext_score` float DEFAULT NULL COMMENT 'MySQL FULLTEXT relevance score',
  `confidence_tier` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'high/medium/low/none',
  `response_time_ms` int DEFAULT NULL COMMENT 'Thời gian xử lý (ms)',
  `method` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'fulltext, rag, gemini, fallback',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `matched_question_id` (`matched_question_id`),
  KEY `idx_created` (`created_at`),
  KEY `idx_method` (`method`),
  CONSTRAINT `rag_performance_log_ibfk_1` FOREIGN KEY (`matched_question_id`) REFERENCES `questions` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Log hiệu suất của RAG system';
